"use client";
import { useParams, useRouter } from "next/navigation";
import { useProducts } from "@/lib/ProductContext";
import { ArrowLeft, ShoppingBag, ShieldCheck, Truck } from "lucide-react";

export default function ProductDetails() {
  const { id } = useParams();
  const { products } = useProducts();
  const router = useRouter();
  
  const product = products.find(p => p.id === Number(id));

  if (!product) return <div className="p-20 text-center">Produto não encontrado.</div>;

  return (
    <div className="min-h-screen bg-white font-sans">
      <div className="max-w-7xl mx-auto px-6 py-12">
        <button onClick={() => router.back()} className="flex items-center gap-2 mb-10 text-gray-500 hover:text-black transition-all">
          <ArrowLeft size={20} /> <span className="font-bold uppercase text-[10px] tracking-widest">Voltar à Loja</span>
        </button>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
          {/* Imagem */}
          <div className="bg-[#F8F8F8] rounded-[60px] overflow-hidden flex items-center justify-center p-12">
            <img src={product.image} alt={product.name} className="w-full h-auto object-contain hover:scale-105 transition-transform duration-700" />
          </div>

          {/* Info */}
          <div className="flex flex-col justify-center">
            <span className="text-[#9C7C50] font-black text-[10px] uppercase tracking-[0.3em] mb-4">{product.category}</span>
            <h1 className="text-5xl font-black text-gray-900 mb-6 leading-tight">{product.name}</h1>
            <p className="text-3xl font-serif italic text-gray-800 mb-8">AOA {product.price.toLocaleString()}</p>
            
            <div className="prose prose-sm text-gray-500 mb-10 leading-relaxed">
              {product.description || "Este produto premium da Nani Cosmético foi formulado com os melhores ingredientes para garantir resultados excepcionais no seu cuidado diário."}
            </div>

            <button className="w-full bg-[#9C7C50] text-white py-6 rounded-3xl font-black uppercase tracking-widest shadow-2xl shadow-[#9C7C50]/30 hover:bg-black transition-all mb-10">
              Adicionar ao Carrinho
            </button>

            {/* Selos de Confiança */}
            <div className="grid grid-cols-2 gap-6 border-t border-gray-100 pt-10">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-gray-50 rounded-2xl text-[#9C7C50]"><Truck size={20}/></div>
                <span className="text-[10px] font-bold uppercase tracking-tighter text-gray-400">Entrega em Luanda</span>
              </div>
              <div className="flex items-center gap-4">
                <div className="p-3 bg-gray-50 rounded-2xl text-[#9C7C50]"><ShieldCheck size={20}/></div>
                <span className="text-[10px] font-bold uppercase tracking-tighter text-gray-400">Original Garantido</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}